// Update after creating the SmartThings virtual motion sensor
// and copying its device ID from account.smartthings.com/tokens or the ST API.
const ST_DEVICE_ID = 'xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx';
const ST_TOKEN     = env.get('ST_TOKEN');

const isOn = (msg.payload === 'ON' || msg.payload === 'on');
const motion = isOn ? 'active' : 'inactive';

msg.url    = 'https://api.smartthings.com/v1/devices/' + ST_DEVICE_ID + '/commands';
msg.method = 'POST';
msg.headers = {
    'Authorization': 'Bearer ' + ST_TOKEN,
    'Content-Type': 'application/json'
};
msg.payload = JSON.stringify({
    commands: [{
        component: 'main',
        capability: 'motionSensor',
        command: 'setMotion',
        arguments: [motion]
    }]
});
msg._motion = motion;
return msg;

// 200 = success, 202 = accepted
if (msg.statusCode !== 200 && msg.statusCode !== 202) {
    node.warn('ST API error ' + msg.statusCode + ': ' + msg.payload);
    return { payload: JSON.stringify({
        component: 'garage-radar',
        category: 'Alert',
        message: 'SmartThings API error ' + msg.statusCode + ' — motion sensor update may have failed (motion: ' + (msg._motion || 'unknown') + ')'
    })};
}
return null;
